interface PQEntry<T> {
  item: T;
  priority: number;
}

export class PriorityQueue<T> {
  private entries: PQEntry<T>[] = [];

  enqueue(item: T, priority: number): void {
    const entry: PQEntry<T> = { item, priority };
    // Insert in sorted position (lower priority number = higher priority)
    let inserted = false;
    for (let i = 0; i < this.entries.length; i++) {
      if (priority < this.entries[i].priority) {
        this.entries.splice(i, 0, entry);
        inserted = true;
        break;
      }
    }
    if (!inserted) {
      this.entries.push(entry);
    }
  }

  dequeue(): T | undefined {
    const entry = this.entries.shift();
    return entry?.item;
  }

  peek(): T | undefined {
    return this.entries[0]?.item;
  }

  get size(): number {
    return this.entries.length;
  }
}
